const VideoBlock = ({ title, desc, tone = "primary", url }) => {
  const bg =
    tone === "primary"
      ? `linear-gradient(135deg, ${ORANGE} 0%, ${ORANGE_DARK} 100%)`
      : tone === "secondary"
      ? `linear-gradient(135deg, ${NAVY} 0%, ${NAVY_DEEP} 100%)`
      : "linear-gradient(135deg, #1A2744 0%, #2d3f6e 100%)";

  return (
    <div
      style={{
        borderRadius: 14,
        overflow: "hidden",
        background: bg,
      }}
    >
      {/* VIDEO */}
      <div
        style={{
          width: "100%",
          aspectRatio: "16/9",
          background: "#000",
        }}
      >
        {url.includes("dropbox") ? (
          <video
            controls
            playsInline
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
            }}
          >
            <source src={url} type="video/mp4" />
          </video>
        ) : (
          <iframe
            width="100%"
            height="100%"
            src={url}
            title={title}
            frameBorder="0"
            allow="autoplay; fullscreen; picture-in-picture"
            allowFullScreen
            style={{
              border: "none",
            }}
          ></iframe>
        )}
      </div>

      {/* TEXT */}
      <div style={{ padding: 16 }}>
        <div
          style={{
            color: "white",
            fontWeight: 800,
            fontSize: 14,
          }}
        >
          {title}
        </div>

        <div
          style={{
            color: "rgba(255,255,255,0.75)",
            fontSize: 12,
            marginTop: 4,
          }}
        >
          {desc}
        </div>
      </div>
    </div>
  );
};
